insert into message_templates (id, title, channel, category, content) values
  ('tpl-1', 'First Outreach WhatsApp', 'WhatsApp', 'First Outreach', 'Halo Pak/Bu, saya sempat melihat website {{company_name}}. Bisnisnya terlihat aktif dan cukup potensial. Saat saya buka lewat HP, ada beberapa bagian yang menurut saya bisa dibuat lebih mudah untuk calon klien menghubungi tim Bapak/Ibu. Saya coba buat mini audit singkat dan contoh improvement untuk halaman utamanya. Boleh saya kirimkan di sini?'),
  ('tpl-2', 'Follow Up 1', 'WhatsApp', 'Follow Up', 'Halo {{contact_person}}, ingin follow up pesan sebelumnya terkait website {{company_name}}. Apakah ada waktu singkat untuk melihat contoh improvement yang sudah saya siapkan untuk {{problem_signal}}?
insert into audits (id, prospect_id, problem_summary, mobile_issue, cta_issue, performance_issue, trust_issue, copywriting_issue, recommendation, audit_status, audit_file_url, mockup_url) values
  ('audit-1', 'prospect-1', 'Copyright 2015, old layout, Yahoo Messenger element, weak mobile/CTA.', true, true, true, false, true, 'Modern B2B import-export company profile + WhatsApp CTA + service pages.', 'Sent', null, null),
  ('audit-2', 'prospect-2', 'Copyright 2016-2020, typo ''marketting'', visitor counter, outdated footer elements.', false, true, false, true, false, 'Redesign contractor profile, project gallery, lead CTA, service landing pages.', 'Draft', null, null),
  ('audit-3', 'prospect-3', 'Powered by Blogger, archive-heavy layout, many SEO-stuffed product posts, weak B2B credibility.', true, true, false, false, false, 'Turn long blog/catalog into clean industrial supplier landing page + product category pages.', 'Not Started', null, null),
  ('audit-4', 'prospect-4', 'Basic WordPress/contact page; likely can improve trust, CTA, and product presentation.', false, true, true, true, false, 'Modern manufacturing profile + product/spec section + inquiry CTA.', 'Sent', null, null),
  ('audit-5', 'prospect-5', 'Older WordPress-style structure; contact is good but landing/lead-gen can be stronger.', true, true, false, false, true, 'Export-ready manufacturing landing page + market segmentation + inquiry funnels.', 'Draft', null, null),
  ('audit-6', 'prospect-6', 'Contact text spacing issue ''marketing @''; page can be more structured; CTA can be sharper.', false, true, false, true, false, 'Industrial workshop profile + service inquiry CTA + project showcase.', 'Not Started', null, null),
  ('audit-7', 'prospect-7', 'Likely basic WordPress company site; opportunity for clearer product catalog and CTA.', true, true, true, false, false, 'Distributor profile + product categories + WhatsApp quick order.', 'Sent', null, null),
  ('audit-8', 'prospect-8', 'Contact page has raw shortcode-like text; UI can be cleaned and project gallery improved.', false, true, false, true, false, 'Interior contractor portfolio redesign + before-after project case studies.', 'Draft', null, null),
  ('audit-9', 'prospect-9', 'Generic construction theme; possible mismatch footer text ''Bosa Construction Industrial''.', true, true, false, false, true, 'Trust cleanup + engineering profile + project/service lead capture.', 'Not Started', null, null),
  ('audit-10', 'prospect-10', 'Powered by Blogger, old copyright 2011, list-based client page.', false, true, true, true, false, 'Convert old Blogger profile into professional contractor portfolio.', 'Sent', null, null),
  ('audit-11', 'prospect-11', 'Proudly powered by WordPress; ecommerce-looking theme may not fit premium B2B marine supplier.', true, true, false, false, false, 'Premium marine supplier landing + product inquiry flow.', 'Draft', null, null),
  ('audit-12', 'prospect-12', 'Already credible; only minor UX/CTA opportunity.', false, true, false, true, false, 'UX audit / landing conversion, not full redesign.', 'Not Started', null, null) on conflict (id) do nothing;
